def table_sheet_normal()
{
/* bis 2014: 02 04 05 06 07 08 09 11 12 13 14 41 42 43 80 */
my normal = FALSE;
my farbe = Feature('Tischmaterial') gt 0 ?  Feature('Tischmaterial') : Feature('Metallfarbe'); 
my normal1 = farbe eq '15' or farbe eq '16' or farbe eq '17' or farbe eq '18' or farbe eq '41' or farbe eq '44' or farbe eq '45' or farbe eq '46' or farbe eq '47'? TRUE:FALSE;
my normal2 = farbe eq '51' or farbe eq '52' or farbe eq '53' ? TRUE:FALSE;
my normal3 = farbe eq '56' or farbe eq '57' or farbe eq '58' ? TRUE:FALSE;
my normal_ht = farbe eq '02' or farbe eq '05' or farbe eq '06' or farbe eq '07' ? TRUE:FALSE;
my normal_kt = farbe eq '2' or farbe eq '5' or farbe eq '6' or farbe eq '7' ? TRUE:FALSE;
my mdf = call table_sheet_mdf();
my heavy = call table_sheet_heavy();
normal = normal1 or normal2 or normal3 or normal_ht or normal_kt or mdf or heavy;
};


def table_sheet_corner()
{
/* bis 2014: 5 6 7 11 12 13 14 */
my normal = FALSE;
my farbe = Feature('Tischmaterial') gt 0 ?  Feature('Tischmaterial') : Feature('Metallfarbe'); 
my normal_kt1 = farbe eq '5' or farbe eq '6' or farbe eq '7' ? TRUE:FALSE;
my normal_kt2 = farbe eq '15'  or farbe eq '16' or farbe eq '17' or farbe eq '18' ? TRUE:FALSE;
normal = normal_kt1 or normal_kt2;
};


def get_material_wood(farbe)
{
/* bis 2014: 02 04 05 06 07 11 12 13 14 41 42 43 */
