my holz_kt = farbe eq '2' or farbe eq '5' or farbe eq '6' or farbe eq '7' ? TRUE:FALSE;
my holz1 = farbe eq '41' or farbe eq '44' or farbe eq '45' or farbe eq '46' or farbe eq '47' ? TRUE:FALSE;
my holz2 = farbe eq '51' or farbe eq '52' or farbe eq '53' or farbe eq '15'  or farbe eq '16' or farbe eq '17' or farbe eq '18' ? TRUE:FALSE;
my kuha3   = farbe eq '56' or farbe eq '57' or farbe eq '58' ? TRUE:FALSE; /* Fenix */
holz =holz_ht or holz_kt or holz1 or holz2 or kuha3 or call table_sheet_mdf();
}


